1173	// Kimi K2 Thinking - uses unique tool call ID format: functions.<name>:<index>
1174	// The ID contains both the function name and an incrementing counter
1175	static common_chat_params common_chat_params_init_kimi_k2(const common_chat_template &    tmpl,
1176	                                                          const autoparser::generation_params & inputs) {
1177	    common_chat_params data;
1178	
1179	    data.prompt             = common_chat_template_direct_apply_impl(tmpl, inputs);
1180	    data.format             = COMMON_CHAT_FORMAT_PEG_NATIVE;
1181	    data.supports_thinking  = true;
1182	    data.preserved_tokens  = {
1183	        "<|tool_calls_section_begin|>",
1184	        "<|tool_calls_section_end|>",
1185	        "<|tool_call_begin|>",
1186	        "<|tool_call_argument_begin|>",
1187	        "<|tool_call_end|>",
1188	        "<think>",
1189	        "</think>",
1190	    };
1191	
1192	    auto has_tools         = inputs.tools.is_array() && !inputs.tools.empty();
1193	    auto extract_reasoning = inputs.reasoning_format != COMMON_REASONING_FORMAT_NONE;
1194	    auto include_grammar   = has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE;
1195	
1196	    const std::string SECTION_BEGIN = "<|tool_calls_section_begin|>";
1197	    const std::string SECTION_END   = "<|tool_calls_section_end|>";
1198	    const std::string CALL_BEGIN    = "<|tool_call_begin|>";
1199	    const std::string ARGS_BEGIN    = "<|tool_call_argument_begin|>";
1200	    const std::string CALL_END      = "<|tool_call_end|>";
1201	
1202	    const std::string THINK_START = "<think>";
1203	    const std::string THINK_END   = "</think>";
1204	
1205	    data.thinking_start_tag = THINK_START;
1206	    data.thinking_end_tag   = THINK_END;
1207	
1208	    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
1209	        // Kimi K2 Thinking format:
1210	        // - Reasoning: <think>{reasoning}</think>
1211	        // - Content: text after reasoning
1212	        // - Tool calls section:
1213	        //   <|tool_calls_section_begin|>
1214	        //   <|tool_call_begin|>functions.<name>:<index><|tool_call_argument_begin|>{json_args}<|tool_call_end|>
1215	        //   ...
1216	        //   <|tool_calls_section_end|>
1217	        // The ID format is: functions.<function_name>:<counter> where counter is 0, 1, 2, ...
1218	
1219	        // Tool call markers
1220	        auto end = p.end();
1221	
1222	        // Note: this model is CRAZY. It can diverge from its supposed tool calling pattern in so many ways it's not funny.
1223	        // For example, it can call tools at the end of reasoning without closing reasoning...
1224	        auto reasoning = extract_reasoning ? p.optional(THINK_START + p.reasoning(
1225	            p.until_one_of({ THINK_END, "<|tool_calls_section_begin|>", "<|tool_call_begin|>" })) +
1226	            p.optional(p.literal(THINK_END))) : p.eps();
1227	        auto generation_prompt = p.prefix(inputs.generation_prompt, THINK_START);
1228	
1229	
1230	        // Content only parser (no tools)
1231	        if (!has_tools || inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_NONE) {
1232	            return generation_prompt + reasoning + p.content(p.rest()) + end;
1233	        }
1234	
1235	        // Build tool call parsers for each available function
1236	        // The ID format is: functions.<name>:<index>
1237	        // We need to match: functions.<name>:<digits>
1238	        auto tool_choice = p.choice();
1239	        foreach_function(inputs.tools, [&](const json & tool) {
1240	            const auto & function = tool.at("function");
1241	            std::string  name     = function.at("name");
1242	            const auto & schema   = function.at("parameters");
1243	
1244	            // Match: functions.<name>:<digits>
1245	            // Capture the full call id (functions.<name>:<digits>) using tool_id tag
1246	            auto tool_id = p.tool_id(p.literal("functions.") + p.tool_name(p.literal(name)) + p.literal(":") + p.chars("[0-9]", 1, -1));
1247	            auto tool_parser = p.tool(
